#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *A = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld",&A[i]);
        __int128 total = 0; // use 128‑bit to avoid overflow in intermediate sum
        for(int l=0;l<=N-3;l++){
            int j=l+1;
            for(int r=l+2;r<N;r++){
                while(j+1<r){
                    long long left1 = A[j]-A[l];
                    long long right1 = A[r]-A[j];
                    long long left2 = A[j+1]-A[l];
                    long long right2 = A[r]-A[j+1];
                    if((__int128)left2*right2 >= (__int128)left1*right1) j++;
                    else break;
                }
                total += (__int128)(A[j]-A[l])*(A[r]-A[j]);
            }
        }
        long long ans = (long long)total; // fits in 64‑bit as per constraints
        printf("%lld\n", ans);
        free(A);
    }
    return 0;
}

