import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] A = new long[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextLong();
            java.math.BigInteger total = java.math.BigInteger.ZERO;
            for (int l = 0; l <= N - 3; l++) {
                int j = l + 1;
                for (int r = l + 2; r < N; r++) {
                    while (j + 1 < r) {
                        long left1 = A[j] - A[l];
                        long right1 = A[r] - A[j];
                        long left2 = A[j + 1] - A[l];
                        long right2 = A[r] - A[j + 1];
                        if (java.math.BigInteger.valueOf(left2).multiply(java.math.BigInteger.valueOf(right2))
                                .compareTo(java.math.BigInteger.valueOf(left1).multiply(java.math.BigInteger.valueOf(right1))) >= 0) {
                            j++;
                        } else break;
                    }
                    long prod = (A[j] - A[l]) * (A[r] - A[j]);
                    total = total.add(java.math.BigInteger.valueOf(prod));
                }
            }
            sb.append(total.toString()).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            if (c == -1) return null;
            do { sb.append((char)c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

