const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(data[idx++]);
  const A = new Array(N);
  for (let i = 0; i < N; i++) A[i] = Number(data[idx++]);
  let total = 0n;
  for (let l = 0; l <= N - 3; l++) {
    let j = l + 1;
    const Al = BigInt(A[l]);
    for (let r = l + 2; r < N; r++) {
      const Ar = BigInt(A[r]);
      while (j + 1 < r) {
        const left1 = BigInt(A[j]) - Al;
        const right1 = Ar - BigInt(A[j]);
        const left2 = BigInt(A[j + 1]) - Al;
        const right2 = Ar - BigInt(A[j + 1]);
        if (left2 * right2 >= left1 * right1) {
          j++;
        } else break;
      }
      const prod = (BigInt(A[j]) - Al) * (Ar - BigInt(A[j]));
      total += prod;
    }
  }
  outputs.push(total.toString());
}
console.log(outputs.join('\n'));
